def setup_logging(
    log_dir: str = "/var/log/myapp",
    log_filename: str = "application.log",
    max_bytes: int = 10 * 1024 * 1024,  # 10 MB
    backup_count: int = 5,
    log_level: int = logging.DEBUG,
    file_permissions: int = 0o640,
    dir_permissions: int = 0o750,
) -> logging.Logger:
    """
    Set up application logging with rotation and file permissions.
    
    Args:
        log_dir: Directory to store log files
        log_filename: Name of the log file
        max_bytes: Maximum size of each log file before rotation
        backup_count: Number of backup log files to keep
        log_level: Logging level
        file_permissions: Unix file permissions for log files (octal)
        dir_permissions: Unix directory permissions for log directory (octal)
    
    Returns:
        Configured logger instance
    """
    # Create log directory if it doesn't exist
    log_path = Path(log_dir)
    try:
        log_path.mkdir(parents=True, exist_ok=True)
        os.chmod(log_dir, dir_permissions)
    except PermissionError:
        # Fallback to user's home directory if /var/log is not writable
        log_dir = os.path.join(Path.home(), ".myapp", "logs")
        log_path = Path(log_dir)
        log_path.mkdir(parents=True, exist_ok=True)
        os.chmod(log_dir, dir_permissions)
        print(f"Warning: Using fallback log directory: {log_dir}", file=sys.stderr)

    log_file = os.path.join(log_dir, log_filename)

    # Create the logger
    logger = logging.getLogger("myapp")
    logger.setLevel(log_level)

    # Prevent adding duplicate handlers
    if logger.handlers:
        return logger

    # Define log format
    detailed_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )

    simple_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )

    # --- Size-based rotating file handler ---
    size_rotating_handler = logging.handlers.RotatingFileHandler(
        filename=log_file,
        maxBytes=max_bytes,
        backupCount=backup_count,
        encoding="utf-8",
    )
    size_rotating_handler.setLevel(logging.DEBUG)
    size_rotating_handler.setFormatter(detailed_formatter)

    # Set file permissions on the log file
    _set_file_permissions(log_file, file_permissions)

    # Custom namer and rotator to set permissions on rotated files
    def rotator(source, dest):
        """Custom rotator that sets file permissions on rotated files."""
        os.rename(source, dest)
        _set_file_permissions(dest, file_permissions)

    def namer(name):
        """Custom namer for rotated log files."""
        return name

    size_rotating_handler.rotator = rotator
    size_rotating_handler.namer = namer

    # --- Time-based rotating file handler (daily rotation) ---
    time_log_file = os.path.join(log_dir, "application_daily.log")
    time_rotating_handler = logging.handlers.TimedRotatingFileHandler(
        filename=time_log_file,
        when="midnight",
        interval=1,
        backupCount=30,  # Keep 30 days of logs
        encoding="utf-8",
        utc=True,
    )
    time_rotating_handler.setLevel(logging.INFO)
    time_rotating_handler.setFormatter(detailed_formatter)
    time_rotating_handler.suffix = "%Y-%m-%d"

    _set_file_permissions(time_log_file, file_permissions)

    # Set rotator for time-based handler too
    def time_rotator(source, dest):
        os.rename(source, dest)
        _set_file_permissions(dest, file_permissions)

    time_rotating_handler.rotator = time_rotator

    # --- Error-only file handler ---
    error_log_file = os.path.join(log_dir, "errors.log")
    error_handler = logging.handlers.RotatingFileHandler(
        filename=error_log_file,
        maxBytes=max_bytes,
        backupCount=backup_count,
        encoding="utf-8",
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(detailed_formatter)

    _set_file_permissions(error_log_file, file_permissions)

    error_handler.rotator = rotator
    error_handler.namer = namer

    # --- Console handler ---
    console_handler = logging.StreamHandler(sys.stdout)
    console_handler.setLevel(logging.INFO)
    console_handler.setFormatter(simple_formatter)

    # Add all handlers to logger
    logger.addHandler(size_rotating_handler)
    logger.addHandler(time_rotating_handler)
    logger.addHandler(error_handler)
    logger.addHandler(console_handler)

    return logger


def _set_file_permissions(filepath: str, permissions: int) -> None:
    """Set file permissions on a log file, creating it if necessary."""
    try:
        # Create file if it doesn't exist
        if not os.path.exists(filepath):
            Path(filepath).touch()
        os.chmod(filepath, permissions)
    except OSError as e:
        print(f"Warning: Could not set permissions on {filepath}: {e}", file=sys.stderr)


def verify_log_permissions(log_dir: str) -> dict:
    """Verify and report permissions on all log files in the directory."""
    results = {}
    log_path = Path(log_dir)

    if not log_path.exists():
        return {"error": f"Directory {log_dir} does not exist"}

    # Check directory permissions
    dir_stat = os.stat(log_dir)
    dir_mode = stat.S_IMODE(dir_stat.st_mode)
    results["directory"] = {
        "path": log_dir,
        "permissions": oct(dir_mode),
        "owner_uid": dir_stat.st_uid,
        "group_gid": dir_stat.st_gid,
    }

    # Check each log file
    results["files"] = []
    for log_file in log_path.glob("*.log*"):
        file_stat = os.stat(log_file)
        file_mode = stat.S_IMODE(file_stat.st_mode)
        results["files"].append({
            "path": str(log_file),
            "permissions": oct(file_mode),
            "size_bytes": file_stat.st_size,
            "owner_uid": file_stat.st_uid,
            "group_gid": file_stat.st_gid,
        })

    return results


class SecureLogFilter(logging.Filter):
    """Filter to redact sensitive information from log messages."""

    SENSITIVE_PATTERNS = [
        "password",
        "secret",
        "token",
        "api_key",
        "credit_card",
        "ssn",
    ]

    def filter(self, record: logging.LogRecord) -> bool:
        if isinstance(record.msg, str):
            for pattern in self.SENSITIVE_PATTERNS:
                if pattern.lower() in record.msg.lower():
                    record.msg = record.msg.replace(
                        record.msg, f"[REDACTED - contains '{pattern}']"
                    )
                    break
        return True


