def generate_large_logs(logger: logging.Logger, count: int = 100):
    """Generate multiple log entries to demonstrate rotation."""
    logger.info("=" * 60)
    logger.info("Generating %d log entries to demonstrate rotation...", count)
    logger.info("=" * 60)

    for i in range(count):
        logger.debug("Debug message #%d: Processing batch item", i)
